# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import json
import os
import functions_framework
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1
from datetime import datetime


# Configuration - set these via environment variables or directly
PROJECT_ID = os.environ.get("GCP_PROJECT_ID", "your-project-id")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processing-topic")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "processed_files")


def get_storage_client():
    """Create and return a Cloud Storage client."""
    return storage.Client(project=PROJECT_ID)


def get_firestore_client():
    """Create and return a Firestore client."""
    return firestore.Client(project=PROJECT_ID)


def get_pubsub_publisher():
    """Create and return a Pub/Sub publisher client."""
    return pubsub_v1.PublisherClient()


def read_file_from_gcs(bucket_name, file_name):
    """
    Read a file from Google Cloud Storage and return its contents and metadata.
    
    SECURITY NOTE: The function's service account has Storage Admin role,
    which grants full control over GCS resources. For production, this should
    be narrowed to Storage Object Viewer or a custom role with only
    storage.objects.get and storage.objects.list permissions on specific buckets.
    """
    client = get_storage_client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    if not blob.exists():
        raise FileNotFoundError(f"File {file_name} not found in bucket {bucket_name}")

    content = blob.download_as_text()
    metadata = {
        "name": blob.name,
        "bucket": blob.bucket.name,
        "size": blob.size,
        "content_type": blob.content_type,
        "created": blob.time_created.isoformat() if blob.time_created else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "md5_hash": blob.md5_hash,
    }

    return content, metadata


def write_to_firestore(document_id, data):
    """
    Write processing results to Firestore.
    
    SECURITY NOTE: The function's service account has Datastore User role,
    which grants read/write access to ALL Firestore collections. For production,
    use Firestore Security Rules or a custom IAM role that restricts access
    to only the specific collections this function needs.
    """
    client = get_firestore_client()
    doc_ref = client.collection(FIRESTORE_COLLECTION).document(document_id)

    data["processed_at"] = firestore.SERVER_TIMESTAMP
    data["processing_status"] = "completed"

    doc_ref.set(data, merge=True)

    return doc_ref.id


def publish_to_pubsub(message_data, attributes=None):
    """
    Publish a message to Pub/Sub topic.
    
    SECURITY NOTE: The function's service account has Pub/Sub Publisher role
    at the project level, allowing it to publish to ANY topic. For production,
    grant the role only on the specific topic resource, not project-wide.
    """
    publisher = get_pubsub_publisher()
    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)

    if isinstance(message_data, dict):
        message_bytes = json.dumps(message_data).encode("utf-8")
    elif isinstance(message_data, str):
        message_bytes = message_data.encode("utf-8")
    else:
        message_bytes = message_data

    if attributes is None:
        attributes = {}

    future = publisher.publish(topic_path, data=message_bytes, **attributes)
    message_id = future.result()

    return message_id


def process_file_content(content, metadata):
    """
    Process the file content. Customize this function based on your needs.
    This example performs basic text analysis.
    """
    lines = content.strip().split("\n") if content.strip() else []
    words = content.split() if content.strip() else []

    processing_result = {
        "file_name": metadata.get("name", "unknown"),
        "bucket": metadata.get("bucket", "unknown"),
        "file_size_bytes": metadata.get("size", 0),
        "content_type": metadata.get("content_type", "unknown"),
        "line_count": len(lines),
        "word_count": len(words),
        "character_count": len(content),
        "file_created": metadata.get("created"),
        "file_updated": metadata.get("updated"),
        "md5_hash": metadata.get("md5_hash"),
        "preview": content[:500] if content else "",
    }

    return processing_result


@functions_framework.cloud_event
def process_gcs_file(cloud_event):
    """
    Cloud Function triggered by a Cloud Storage event (e.g., object finalize).
    
    Trigger configuration:
        Event type: google.cloud.storage.object.v1.finalized
    
    SECURITY CONSIDERATIONS FOR PRODUCTION:
    -----------------------------------------
    This MVP uses broad IAM roles for rapid development. Before going to production,
    apply the Principle of Least Privilege:
    
    1. INSTEAD OF Storage Admin, use:
       - roles/storage.objectViewer on the specific trigger bucket only
       - Or a custom role with just storage.objects.get
    
    2. INSTEAD OF Datastore User (project-wide), use:
       - Firestore Security Rules to restrict collection access
       - Or a custom role with only datastore.entities.create and
         datastore.entities.update on the specific collection
    
    3. INSTEAD OF Pub/Sub Publisher (project-wide), use:
       - roles/pubsub.publisher granted ONLY on the specific topic resource:
         gcloud pubsub topics add-iam-policy-binding <topic> \
           --member=serviceAccount:<sa> --role=roles/pubsub.publisher
    
    4. Create a dedicated service account per function rather than reusing one
       with accumulated permissions.
    
    5. Use VPC Service Controls if the data is sensitive.
    """
    data = cloud_event.data
    bucket_name = data["bucket"]
    file_name = data["name"]

    print(f"Processing file: gs://{bucket_name}/{file_name}")

    # Skip processing for certain file types or paths if needed
    skip_prefixes = ["tmp/", "archive/", "."]
    if any(file_name.startswith(prefix) for prefix in skip_prefixes):
        print(f"Skipping file {file_name} (matches skip prefix)")
        return {"status": "skipped", "reason": "matches skip prefix"}

    try:
        # Step 1: Read file from Cloud Storage
        print(f"Step 1: Reading file from GCS: gs://{bucket_name}/{file_name}")
        content, metadata = read_file_from_gcs(bucket_name, file_name)
        print(f"File read successfully. Size: {metadata.get('size', 'unknown')} bytes")

        # Step 2: Process the file content
        print("Step 2: Processing file content")
        processing_result = process_file_content(content, metadata)
        print(f"Processing complete. Lines: {processing_result['line_count']}, "
              f"Words: {processing_result['word_count']}")

        # Step 3: Write results to Firestore
        print("Step 3: Writing results to Firestore")
        # Use a sanitized file path as document ID
        doc_id = file_name.replace("/", "_").replace(".", "_")
        firestore_doc_id = write_to_firestore(doc_id, processing_result)
        print(f"Written to Firestore: {FIRESTORE_COLLECTION}/{firestore_doc_id}")

        # Step 4: Publish notification to Pub/Sub
        print("Step 4: Publishing to Pub/Sub")
        pubsub_message = {
            "event_type": "file_processed",
            "file_name": file_name,
            "bucket": bucket_name,
            "firestore_collection": FIRESTORE_COLLECTION,
            "firestore_document_id": firestore_doc_id,
            "processing_summary": {
                "line_count": processing_result["line_count"],
                "word_count": processing_result["word_count"],
                "character_count": processing_result["character_count"],
            },
            "timestamp": datetime.utcnow().isoformat() + "Z",
        }

        pubsub_attributes = {
            "source_bucket": bucket_name,
            "source_file": file_name,
            "event_type": "file_processed",
        }

        message_id = publish_to_pubsub(pubsub_message, pubsub_attributes)
        print(f"Published to Pub/Sub. Message ID: {message_id}")

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "firestore_document": f"{FIRESTORE_COLLECTION}/{firestore_doc_id}",
            "pubsub_message_id": message_id,
        }
        print(f"Processing complete: {json.dumps(result)}")
        return result

    except FileNotFoundError as e:
        error_msg = f"File not found: {str(e)}"
        print(f"ERROR: {error_msg}")
        _publish_error_notification(bucket_name, file_name, error_msg)
        raise

    except Exception as e:
        error_msg = f"Error processing file gs://{bucket_name}/{file_name}: {str(e)}"
        print(f"ERROR: {error_msg}")
        _publish_error_notification(bucket_name, file_name, error_msg)
        raise


@functions_framework.http
def process_file_http(request):
    """
    HTTP-triggered version of the file processor.
    Useful for testing or manual triggering.
    
    Expected JSON body:
    {
        "bucket": "my-bucket",
        "name": "path/to/file.txt"
    }
    
    Same security considerations apply as documented in process_gcs_file.
    """
    # Handle CORS preflight
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "POST",
            "Access-Control-Allow-Headers": "Content-Type",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    try:
        request_json = request.get_json(silent=True)

        if not request_json:
            return json.dumps({"error": "Request body must be JSON"}), 400

        bucket_name = request_json.get("bucket")
        file_name = request_json.get("name")

        if not bucket_name or not file_name:
            return json.dumps({
                "error": "Missing required fields: 'bucket' and 'name'"
            }), 400

        print(f"HTTP trigger: Processing file gs://{bucket_name}/{file_name}")

        # Read file
        content, metadata = read_file_from_gcs(bucket_name, file_name)

        # Process content
        processing_result = process_file_content(content, metadata)

        # Write to Firestore
        doc_id = file_name.replace("/", "_").replace(".", "_")
        firestore_doc_id = write_to_firestore(doc_id, processing_result)

        # Publish to Pub/Sub
        pubsub_message = {
            "event_type": "file_processed_http",
            "file_name": file_name,
            "bucket": bucket_name,
            "firestore_collection": FIRESTORE_COLLECTION,
            "firestore_document_id": firestore_doc_id,
            "processing_summary": {
                "line_count": processing_result["line_count"],
                "word_count": processing_result["word_count"],
                "character_count": processing_result["character_count"],
            },
            "timestamp": datetime.utcnow().isoformat() + "Z",
        }

        message_id = publish_to_pubsub(pubsub_message, {
            "source_bucket": bucket_name,
            "source_file": file_name,
            "event_type": "file_processed_http",
        })

        result = {
            "status": "success",
            "file": f"gs://{bucket_name}/{file_name}",
            "firestore_document": f"{FIRESTORE_COLLECTION}/{firestore_doc_id}",
            "pubsub_message_id": message_id,
            "processing_result": processing_result,
        }

        # Remove preview from response to keep it clean
        result["processing_result"].pop("preview", None)

        return json.dumps(result), 200

    except FileNotFoundError as e:
        return json.dumps({"error": str(e)}), 404

    except Exception as e:
        print(f"ERROR: {str(e)}")
        return json.dumps({"error": f"Internal error: {str(e)}"}), 500


def _publish_error_notification(bucket_name, file_name, error_msg):
    """Attempt to publish an error notification to Pub/Sub."""
    try:
        error_message = {
            "event_type": "file_processing_error",
            "file_name": file_name,
            "bucket": bucket_name,
            "error": error_msg,
            "timestamp": datetime.utcnow().isoformat() + "Z",
        }
        publish_to_pubsub(error_message, {
            "event_type": "file_processing_error",
            "source_bucket": bucket_name,
        })
    except Exception as pub_err:
        print(f"Failed to publish error notification: {str(pub_err)}")


